// ═══════════════════════════════════════════════════════
// I-REP v3.0 — Preparar archivos para deploy en Railway
// Ejecutar desde la RAIZ del repo geronimoak/repuestos:
//   node prepare_deploy.js
//   git add . && git commit -m 'Deploy I-REP v3.0' && git push
// ═══════════════════════════════════════════════════════
const fs=require('fs'),path=require('path');
const pub=path.join(__dirname,'public');
if(!fs.existsSync(pub)) fs.mkdirSync(pub,{recursive:true});

fs.writeFileSync(path.join(__dirname,'server.js'),Buffer.from('','base64'));
console.log('✓ server.js');
fs.writeFileSync(path.join(__dirname,'package.json'),Buffer.from('','base64'));
console.log('✓ package.json');
fs.writeFileSync(path.join(__dirname,'.gitignore'),Buffer.from('','base64'));
console.log('✓ .gitignore');
fs.writeFileSync(path.join(__dirname,'railway.json'),Buffer.from('','base64'));
console.log('✓ railway.json');
fs.writeFileSync(path.join(__dirname,'DEPLOY_INSTRUCCIONES.txt'),Buffer.from('','base64'));
console.log('✓ DEPLOY_INSTRUCCIONES.txt');
fs.writeFileSync(path.join(pub,'index.html'),Buffer.from('','base64'));
console.log('✓ public/index.html');
fs.writeFileSync(path.join(pub,'app.js'),Buffer.from('','base64'));
console.log('✓ public/app.js');
fs.writeFileSync(path.join(pub,'styles.css'),Buffer.from('','base64'));
console.log('✓ public/styles.css');
fs.writeFileSync(path.join(pub,'analytics-module.js'),Buffer.from('','base64'));
console.log('✓ public/analytics-module.js');
fs.writeFileSync(path.join(pub,'novedades-module.js'),Buffer.from('','base64'));
console.log('✓ public/novedades-module.js');
fs.writeFileSync(path.join(pub,'cap-module.js'),Buffer.from('','base64'));
console.log('✓ public/cap-module.js');
fs.writeFileSync(path.join(pub,'logo.png'),Buffer.from('','base64'));
console.log('✓ public/logo.png');
fs.writeFileSync(path.join(pub,'favicon.svg'),Buffer.from('','base64'));
console.log('✓ public/favicon.svg');

console.log('');
console.log('═══════════════════════════════════════════════');
console.log('✅ Archivos listos para deploy');
console.log('');
console.log('PRÓXIMOS PASOS:');
console.log('1. git add .');
console.log('   git commit -m Deploy I-REP v3.0');
console.log('   git push origin main');
console.log('');
console.log('2. railway.app → Nuevo proyecto → Repositorio de GitHub');
console.log('   Seleccionar: geronimoak/repuestos');
console.log('');
console.log('3. En Railway → Variables → agregar:');
console.log('   GOOGLE_CREDENTIALS_JSON = (ver DEPLOY_INSTRUCCIONES.txt)');
console.log('');
console.log('4. Railway deploya automático en ~2 minutos');
console.log('═══════════════════════════════════════════════');